VALUES
  ('optometrist-moex-03614', 'optometrist', 'optometrist-moex-106-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '用眼鏡矯正散光，下列建議何者錯誤？', '["影像扭曲造成的不適，通常是雙眼的現象，故遮住一眼可以確定是否因此不適", "如果影像扭曲造成不適，可以嘗試將柱鏡的軸度轉往90°或180°", "為減少影像扭曲，可以嘗試減少柱鏡的度數", "如果影像扭曲造成不適無法解除，即使用散光的隱形眼鏡矯正也是一樣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "fb0b0bc8f8ae", "answer_pdf_sha1": "5b57eb0a441a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
